+import AppKit
+import SwiftUI
+
+@MainActor
+final class ShortcutRecorderController: ObservableObject {
+    @Published private(set) var currentChord: HotkeyChord
+    @Published private(set) var isRecording = false
+
+    private let beginCapture: @MainActor () -> Void
+    private let endCapture: @MainActor () -> Void
+    private let onChange: @MainActor (HotkeyChord) -> Void
+    private let stateMachine = ShortcutCaptureStateMachine()
+    private var previewChord: HotkeyChord?
+
+    init(
+        currentChord: HotkeyChord,
+        beginCapture: @escaping @MainActor () -> Void,
+        endCapture: @escaping @MainActor () -> Void,
+        onChange: @escaping @MainActor (HotkeyChord) -> Void
+    ) {
+        self.currentChord = currentChord
+        self.beginCapture = beginCapture
+        self.endCapture = endCapture
+        self.onChange = onChange
+    }
+
+    var buttonTitle: String {
+        if isRecording, previewChord == nil {
+            return "Press Shortcut"
+        }
+
+        return displayedChord.compactDisplayString
+    }
+
+    var displayedKeyLabels: [String] {
+        displayedChord.sortedKeys.map(\.compactDisplayName)
+    }
+
+    var showsInstructions: Bool {
+        isRecording
+    }
+
+    func setCurrentChord(_ chord: HotkeyChord) {
+        currentChord = chord
+        if !isRecording {
+            previewChord = nil
+        }
+    }
+
+    func beginRecording() {
+        guard !isRecording else {
+            return
+        }
+
+        stateMachine.reset()
+        previewChord = nil
+        isRecording = true
+        beginCapture()
+    }
+
+    func handleModifierChange(_ key: HotkeyKey) {
+        guard isRecording else {
+            return
+        }
+
+        if stateMachine.pressedKeys.contains(key) {
+            process(.keyReleased(key))
+        } else {
+            process(.keyPressed(key))
+        }
+    }
+
+    func handleKeyDown(_ key: HotkeyKey) {
+        guard isRecording else {
+            return
+        }
+
+        if key == .escape && stateMachine.capturedKeys.isEmpty {
+            cancelRecording()
+            return
+        }
+
+        process(.keyPressed(key))
+    }
+
+    func handleKeyUp(_ key: HotkeyKey) {
+        guard isRecording else {
+            return
+        }
+
+        process(.keyReleased(key))
+    }
+
+    func disappear() {
+        guard isRecording else {
+            return
+        }
+
+        cancelRecording()
+    }
+
+    private var displayedChord: HotkeyChord {
+        previewChord ?? currentChord
+    }
+
+    private func process(_ event: ShortcutCaptureEvent) {
+        if let chord = stateMachine.process(event) {
+            commitRecording(chord)
+            return
+        }
+
+        previewChord = stateMachine.capturedKeys.isEmpty ? nil : try? HotkeyChord(keys: stateMachine.capturedKeys)
+        objectWillChange.send()
+    }
+
+    private func commitRecording(_ chord: HotkeyChord) {
+        currentChord = chord
+        previewChord = nil
+        stateMachine.reset()
+        isRecording = false
+        endCapture()
+        onChange(chord)
+    }
+
+    private func cancelRecording() {
+        previewChord = nil
+        stateMachine.reset()
+        isRecording = false
+        endCapture()
+    }
+}
+
+struct ShortcutRecorderView: View {
+    let title: String
+    @ObservedObject var controller: ShortcutRecorderController
+    @State private var eventMonitor: Any?
+
+    var body: some View {
+        VStack(alignment: .leading, spacing: 8) {
+            Text(title)
+                .font(.subheadline.weight(.semibold))
+
+            recorderButton
+
+            if controller.showsInstructions {
+                Text("Press the full chord, then release. Press Escape to cancel.")
+                    .font(.footnote)
+                    .foregroundStyle(.secondary)
+            }
+        }
+        .onChange(of: controller.isRecording) { _, isRecording in
+            if isRecording {
+                installEventMonitor()
+            } else {
+                removeEventMonitor()
+            }
+        }
+        .onDisappear {
+            removeEventMonitor()
+            controller.disappear()
+        }
+    }
+
+    @ViewBuilder
+    private var recorderButton: some View {
+        let button = Button {
+            controller.beginRecording()
+        } label: {
+            if controller.isRecording && controller.buttonTitle == "Press Shortcut" {
+                Text(controller.buttonTitle)
+                    .frame(maxWidth: .infinity, alignment: .center)
+            } else {
+                HStack(spacing: 6) {
+                    ForEach(Array(controller.displayedKeyLabels.enumerated()), id: \.offset) { index, label in
+                        if index > 0 {
+                            Text("+")
+                                .foregroundStyle(.secondary)
+                        }
+                        KeyCapView(
+                            label: label,
+                            isHighlighted: controller.isRecording,
+                            highlightColor: controller.isRecording ? .red : .orange
+                        )
+                    }
+                }
+                .frame(maxWidth: .infinity, alignment: .center)
+            }
+        }
+        .tint(.orange)
+
+        if controller.isRecording {
+            button.buttonStyle(.borderedProminent)
+        } else {
+            button.buttonStyle(.bordered)
+        }
+    }
+
+    private func installEventMonitor() {
+        guard eventMonitor == nil else {
+            return
+        }
+
+        eventMonitor = NSEvent.addLocalMonitorForEvents(matching: [.flagsChanged, .keyDown, .keyUp]) { event in
+            handle(event)
+        }
+    }
+
+    private func removeEventMonitor() {
+        guard let eventMonitor else {
+            return
+        }
+
+        NSEvent.removeMonitor(eventMonitor)
+        self.eventMonitor = nil
+    }
+
+    private func handle(_ event: NSEvent) -> NSEvent? {
+        guard let key = HotkeyKey(rawValue: UInt16(event.keyCode)) else {
+            return nil
+        }
+
+        switch event.type {
+        case .flagsChanged:
+            controller.handleModifierChange(key)
+            return nil
+        case .keyDown:
+            controller.handleKeyDown(key)
+            return nil
+        case .keyUp:
+            controller.handleKeyUp(key)
+            return nil
+        default:
+            return event
+        }
+    }
+}
+
+struct KeyCapView: View {
+    let label: String
+    var isHighlighted = false
+    var highlightColor: Color = .orange
+
+    var body: some View {
+        Text(label)
+            .font(.callout.weight(isHighlighted ? .semibold : .regular))
+            .foregroundStyle(isHighlighted ? Color.white : Color.secondary)
+            .padding(.horizontal, 10)
+            .padding(.vertical, 6)
+            .background(
+                RoundedRectangle(cornerRadius: 10)
+                    .fill(isHighlighted ? highlightColor : Color(nsColor: .controlBackgroundColor))
+            )
+            .animation(.easeInOut(duration: 0.2), value: isHighlighted)
+    }
+}

